-- 1. emp 테이블 생성
CREATE TABLE emp (
    empno NUMBER PRIMARY KEY,        -- 사원 ID
    ename VARCHAR(50) NOT NULL, -- 사원 이름
    job VARCHAR(50) NOT NULL,-- 직급
    hiredate DATE NOT NULL,       -- 입사일
    sal NUMBER(10,2) NOT NULL,-- 급여
    deptno NUMBER NOT NULL           -- 부서 ID
);

